let drones = flow.get("drones") || {};

function xyToLatLon(x, y) {
    const ISEP_LAT = 41.1779;
    const ISEP_LON = -8.6080;
    const AREA_SIZE_METERS = 100;

    const offsetX = ((x - 50) / 100) * AREA_SIZE_METERS;
    const offsetY = ((y - 50) / 100) * AREA_SIZE_METERS;

    const lat = ISEP_LAT + (offsetY / 111320);
    const lon = ISEP_LON + (offsetX / (111320 * Math.cos(ISEP_LAT * Math.PI / 180)));

    return { lat, lon };
}

const data = msg.payload.data || [];

for (const drone of data) {
    let id = drone.id;

    if (id === "Drone1" || id === "drone1") {
        id = "Drone:001";
    }

    if (id === "Drone2" || id === "drone2") {
        id = "Drone:002";
    }

    const rawX = drone.x?.value;
    const rawY = drone.y?.value;

    if (rawX === undefined || rawY === undefined) continue;

    const x = Math.max(0, Math.min(100, Number(rawX)));
    const y = Math.max(0, Math.min(100, Number(rawY)));

    const pos = xyToLatLon(x, y);

    drones[id] = {
        id,
        type: drone.type,
        battery: drone.battery?.value,
        status: drone.status?.value,
        x,
        y,
        lat: pos.lat,
        lon: pos.lon
    };
}

flow.set("drones", drones);

const dashboardMsg = {
    payload: Object.values(drones)
};

let responseMsg = null;

if (msg.req && msg.res) {
    responseMsg = {
        req: msg.req,
        res: msg.res,
        statusCode: 200,
        payload: {
            status: "received"
        }
    };
}

return [dashboardMsg, dashboardMsg, responseMsg];

const drones = msg.payload || [];
let alreadyAlerted = flow.get("alreadyAlerted") || {};

for (const drone of drones) {
    const battery = drone.battery;

    if (battery !== undefined && battery <= 20) {
        if (!alreadyAlerted[drone.id]) {
            alreadyAlerted[drone.id] = true;
            flow.set("alreadyAlerted", alreadyAlerted);

            return {
                payload: {
                    title: "Low Battery Warning",
                    message: `${drone.id} battery is low: ${battery}%`,
                    droneId: drone.id,
                    battery: battery,
                    severity: battery <= 10 ? "critical" : "warning"
                }
            };
        }
    } else {
        alreadyAlerted[drone.id] = false;
    }
}

flow.set("alreadyAlerted", alreadyAlerted);
return null;
